def apply_subst_to_term(term: OTerm, subst: Dict[str, OTerm]) -> OTerm:
    """Apply a simultaneous substitution to an OTerm."""
    result = term
    for var, replacement in subst.items():
        result = subst_in_term(result, var, replacement)
    return result


